 namespace Pmpr\Common\Foundation\Decorator; class DecoratorOption extends Decorator { public static function delete($WonJK) { return delete_option($WonJK); } public static function add($WonJK, $fNG64) { return add_option($WonJK, $fNG64); } public static function get($WonJK, $zEPQ8 = false) { return get_option($WonJK, $zEPQ8); } public static function getSite($WonJK, $zEPQ8 = false) { get_site_option($WonJK, $zEPQ8); } public static function update($WonJK, $fNG64, $APQYm = null) { return update_option($WonJK, $fNG64, $APQYm); } }
